import React, { useState, useRef, useEffect } from 'react';
import './Navbar.css';

export const Navbar = ({ cartCount }) => {
  const [menuAbierto, setMenuAbierto]       = useState(false);
  const [busqueda, setBusqueda]             = useState('');
  const [dropdownAbierto, setDropdownAbierto] = useState(null);
  const timeoutRef = useRef(null);

  const categorias = [
    {
      nombre: 'Laptops',
      href: '#laptops',
      subcategorias: [
        { nombre: 'Para estudiantes', badge: 'Popular' },
        { nombre: 'Para oficina' },
        { nombre: 'Gaming',           badge: 'Oferta'  },
        { nombre: 'Ultradelgadas' },
      ],
    },
    {
      nombre: 'Monitores',
      href: '#monitores',
      subcategorias: [
        { nombre: 'Full HD' },
        { nombre: '4K' },
        { nombre: 'Gaming 144Hz+', badge: 'Oferta' },
        { nombre: 'Curvos' },
      ],
    },
    {
      nombre: 'Teclados',
      href: '#teclados',
      subcategorias: [
        { nombre: 'Mecánicos',    badge: 'Nuevo' },
        { nombre: 'Inalámbricos' },
        { nombre: 'Gaming RGB' },
      ],
    },
    {
      nombre: 'Mouse',
      href: '#mouse',
      subcategorias: [
        { nombre: 'Inalámbrico' },
        { nombre: 'Gaming',      badge: 'Oferta' },
        { nombre: 'Ergonómico' },
      ],
    },
    {
      nombre: 'Auriculares',
      href: '#auriculares',
      subcategorias: [
        { nombre: 'Gaming',        badge: 'Nuevo' },
        { nombre: 'Inalámbricos' },
        { nombre: 'Con micrófono' },
      ],
    },
  ];

  // Cierra el dropdown al hacer clic fuera del navbar
  useEffect(() => {
    const handleClickFuera = (e) => {
      if (!e.target.closest('.navbar-categorias')) {
        setDropdownAbierto(null);
      }
    };
    document.addEventListener('mousedown', handleClickFuera);
    return () => document.removeEventListener('mousedown', handleClickFuera);
  }, []);

  const abrirDropdown = (nombre) => {
    clearTimeout(timeoutRef.current);
    setDropdownAbierto(nombre);
  };

  const cerrarDropdownConDelay = () => {
    timeoutRef.current = setTimeout(() => setDropdownAbierto(null), 200);
  };

  const handleBusqueda = (e) => {
    e.preventDefault();
    console.log('Buscando:', busqueda);
  };

  return (
    <header>
      {/* Promo */}
      <div className="promo-bar">
        Envío gratis en Lima desde S/ 199
        <span className="promo-separador">|</span>
        Hasta 12 cuotas sin intereses
        <span className="promo-separador">|</span>
        Garantía oficial 12 meses
      </div>

      {/* Navbar principal */}
      <nav className="navbar">
        <a href="#inicio" className="navbar-logo">
          Tech<span>Store</span>
        </a>

        <form className="navbar-search" onSubmit={handleBusqueda}>
          <input
            type="text"
            placeholder="Buscar laptops, monitores, teclados..."
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
          />
          <button type="submit" aria-label="Buscar">🔍</button>
        </form>

        <div className="navbar-acciones">
          <a href="#cuenta" className="navbar-cuenta">
            <span className="icono-cuenta">👤</span>
            Mi cuenta
          </a>
          <a href="#carrito" className="navbar-carrito">
            🛒 Carrito
            {cartCount > 0 && (
              <span className="carrito-badge">{cartCount}</span>
            )}
          </a>
        </div>

        <button
          className="navbar-hamburguesa"
          onClick={() => setMenuAbierto(!menuAbierto)}
          aria-label="Abrir menú"
        >
          ☰
        </button>
      </nav>

      {/* Categorías */}
      <div className={`navbar-categorias ${menuAbierto ? 'abierto' : ''}`}>
        <ul className="categorias-lista">

          {categorias.map((cat) => (
            <li
              key={cat.nombre}
              className="categoria-item"
              onMouseEnter={() => abrirDropdown(cat.nombre)}
              onMouseLeave={cerrarDropdownConDelay}
            >
              {/* Título de categoría */}
              <a href={cat.href} className="categoria-link">
                {cat.nombre} <span className="chevron">▾</span>
              </a>

              {/* Submenú — React lo monta/desmonta según el estado */}
              {dropdownAbierto === cat.nombre && (
                <ul
                  className="dropdown"
                  onMouseEnter={() => abrirDropdown(cat.nombre)}
                  onMouseLeave={cerrarDropdownConDelay}
                >
                  {cat.subcategorias.map((sub) => (
                    <li key={sub.nombre}>
                      <a href={cat.href}>
                        {sub.nombre}
                        {sub.badge && (
                          <span
                            className={`badge ${
                              sub.badge === 'Nuevo' ? 'badge-nuevo' : 'badge-oferta'
                            }`}
                          >
                            {sub.badge}
                          </span>
                        )}
                      </a>
                    </li>
                  ))}
                </ul>
              )}
            </li>
          ))}

          <li className="categoria-item">
            <a href="#ofertas" className="categoria-link">Ofertas</a>
          </li>
          <li className="categoria-item">
            <a href="#remates" className="categoria-link categoria-remates">
              🔥 Remates
            </a>
          </li>

        </ul>
      </div>
    </header>
  );
};
